const parseStart = (s) => {
  // Accept "YYYY-MM" or "YYYY-MM-DD"
  const parts = String(s).split("-");
  return { year: Number(parts[0]) || 2025, month: (Number(parts[1]) || 1) - 1 };
};
const buildMonths = (startDate, count) => {
  const { year, month } = parseStart(startDate);
  return Array.from({ length: count }, (_, i) => {
    const m = new Date(year, month + i, 1);
    return { key: `${m.getFullYear()}-${String(m.getMonth() + 1).padStart(2, "0")}`, label: m.toLocaleDateString("en-US", { month: "short", year: "2-digit" }), date: m, year: m.getFullYear() };
  });
};

