const groupSectionIds = (gId) => BUDGET_GROUPS.find(g => g.id === gId)?.sections.map(s => s.id) || [];
const findSectionInGroups = (sId) => {
  for (const g of BUDGET_GROUPS) { const s = g.sections.find(s => s.id === sId); if (s) return { group: g, section: s }; }
  return null;
};

const buildPhaseAssignment = (phases, monthKeys) => {
  const pa = {};
  let mi = 0;
  phases.forEach((p) => { for (let j = 0; j < p.months && mi < monthKeys.length; j++, mi++) pa[monthKeys[mi]] = p.id; });
  return pa;
};

