/* ─── Style Tokens ─── */
const S = { bg: "#020617", sf: "#0f172a", bd: "#1e293b", bd2: "#334155", tx: "#e2e8f0", dim: "#64748b", mut: "#475569", acc: "#6366f1", grn: "#10b981", red: "#ef4444", yel: "#f59e0b", fn: "'DM Sans',sans-serif", mo: "'JetBrains Mono',monospace" };

/* ─── Tiny UI ─── */
const renderMd = (text) => {
  if (!text) return "";
  let h = String(text).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
  h = h.replace(/```([\s\S]*?)```/g, (m, c) => '<pre style="background:#0f172a;padding:8px 10px;border-radius:6px;font-family:monospace;font-size:10px;overflow-x:auto;margin:4px 0;border:1px solid #1e293b;white-space:pre-wrap">' + c.trim() + '</pre>');
  h = h.replace(/`([^`]+)`/g, '<code style="background:#1e293b;padding:1px 5px;border-radius:3px;font-family:monospace;font-size:10px">$1</code>');
  h = h.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  h = h.replace(/\*(.+?)\*/g, '<em>$1</em>');
  h = h.replace(/^### (.+)$/gm, '<div style="font-size:13px;font-weight:700;margin:6px 0 3px">$1</div>');
  h = h.replace(/^## (.+)$/gm, '<div style="font-size:14px;font-weight:800;margin:8px 0 4px">$1</div>');
  h = h.replace(/^# (.+)$/gm, '<div style="font-size:15px;font-weight:800;margin:8px 0 4px">$1</div>');
  h = h.replace(/^[\-\*] (.+)$/gm, '<div style="padding-left:12px;margin:2px 0">\u2022 $1</div>');
  h = h.replace(/^(\d+)\. (.+)$/gm, '<div style="padding-left:12px;margin:2px 0"><strong style="color:#6366f1">$1.</strong> $2</div>');
  h = h.replace(/\n/g, '<br/>');
  return h;
};
const blendBg = (hex, alpha) => {
  const r = parseInt(hex.slice(1,3),16), g = parseInt(hex.slice(3,5),16), b = parseInt(hex.slice(5,7),16);
  const br = 2, bg2 = 6, bb = 23;
  const a = alpha;
  return "#" + [Math.round(r*a+br*(1-a)), Math.round(g*a+bg2*(1-a)), Math.round(b*a+bb*(1-a))].map(v => v.toString(16).padStart(2,"0")).join("");
};

