// Ledger tab definitions
const LEDGER_TABS = [
  
  { id: "all", label: "All Records" },
  { id: "dev", label: "Development Costs", groups: ["Development Costs"] },
  { id: "port", label: "Porting Costs", groups: ["Porting Costs"] },
  { id: "ext", label: "External Support Costs", groups: ["External Support Costs"] },
];

// Map each selectable category value to its top-level group
const CAT_TO_GROUP = {};
const CAT_TO_SUBGROUP = {};
LEDGER_CATEGORIES.forEach(g => {
  CAT_TO_GROUP[g.group] = g.group;
  (g.items || []).forEach(item => {
    if (typeof item === "string") { CAT_TO_GROUP[item] = g.group; CAT_TO_SUBGROUP[item] = item; }
    else if (item.label) { CAT_TO_GROUP[item.label] = g.group; CAT_TO_SUBGROUP[item.label] = item.label; }
    else if (item.sub) {
      CAT_TO_GROUP[item.sub] = g.group; CAT_TO_SUBGROUP[item.sub] = item.sub;
      (item.items || []).forEach(s => { CAT_TO_GROUP[s] = g.group; CAT_TO_SUBGROUP[s] = item.sub; });
    }
  });
});

// Get sub-category groupings for a tab
function getSubCatsForTab(tabId) {
  const tab = LEDGER_TABS.find(t => t.id === tabId);
  if (!tab || !tab.groups) return null;
  const results = [];
  tab.groups.forEach(gName => {
    const g = LEDGER_CATEGORIES.find(c => c.group === gName);
    if (!g) { results.push({ key: gName, label: gName }); return; }
    if (!g.items || g.items.length === 0) { results.push({ key: gName, label: gName }); return; }
    g.items.forEach(item => {
      if (typeof item === "string") results.push({ key: item, label: item });
      else if (item.label) results.push({ key: item.label, label: item.label });
      else if (item.sub) {
        results.push({ key: item.sub, label: item.sub });
        // Don't expand sub-sub-items as separate groups — they're nested under the sub
      }
    });
  });
  return results;
}

/* ─── PhaseEditor ─── */
function PhaseEditor({ phases, onChange, monthCount }) {
  const isMobile = typeof window !== "undefined" && window.innerWidth < 768;
  const totalAssigned = phases.reduce((s, p) => s + p.months, 0);
  const remaining = monthCount - totalAssigned;

  const updatePhase = (idx, field, value) => {
    const next = phases.map((p, i) => i === idx ? { ...p, [field]: field === "months" ? Math.max(0, Number(value) || 0) : value } : p);
    onChange(next);
  };
  const addPhase = () => {
    const id = "phase_" + uuid();
    const colorIdx = phases.length % PHASE_COLORS.length;
    onChange([...phases, { id, name: "New Phase", color: PHASE_COLORS[colorIdx], months: Math.max(0, remaining) }]);
  };
  const removePhase = (idx) => { if (phases.length > 1) onChange(phases.filter((_, i) => i !== idx)); };
  const movePhase = (idx, dir) => {
    const next = [...phases];
    const target = idx + dir;
    if (target < 0 || target >= next.length) return;
    [next[idx], next[target]] = [next[target], next[idx]];
    onChange(next);
  };

  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12, flexWrap: "wrap", gap: 8 }}>
        <div style={{ fontSize: 12, color: S.dim }}>
          Total: <strong style={{ color: totalAssigned === monthCount ? S.grn : S.yel, fontFamily: S.mo }}>{totalAssigned}</strong> / {monthCount} months
          {remaining !== 0 && <span style={{ color: remaining > 0 ? S.yel : S.red, marginLeft: 8 }}>({remaining > 0 ? `${remaining} unassigned` : `${Math.abs(remaining)} over!`})</span>}
        </div>
        <Btn small primary onClick={addPhase}>+ Add Phase</Btn>
      </div>

      {/* Visual timeline bar */}
      <div style={{ display: "flex", borderRadius: 6, overflow: "hidden", marginBottom: 16, height: 28 }}>
        {phases.map((p, i) => {
          const pct = monthCount > 0 ? (p.months / monthCount) * 100 : 0;
          return pct > 0 ? (
            <div key={p.id} style={{ width: `${pct}%`, background: p.color, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 9, fontWeight: 700, color: "#fff", whiteSpace: "nowrap", overflow: "hidden", borderRight: i < phases.length - 1 ? "1px solid rgba(0,0,0,0.3)" : "none", minWidth: 2 }}>
              {pct > 6 ? `${p.name} (${p.months})` : p.months}
            </div>
          ) : null;
        })}
        {remaining > 0 && (
          <div style={{ width: `${(remaining / monthCount) * 100}%`, background: "#1e293b", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 9, color: S.dim, borderLeft: "1px dashed #475569" }}>
            Unassigned ({remaining})
          </div>
        )}
      </div>

      {/* Phase list */}
      <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
        {phases.map((p, i) => (
          <div key={p.id} style={{ display: "grid", gridTemplateColumns: "32px 28px 12px 1fr 80px 32px 32px", gap: 6, alignItems: "center" }}>
            <div style={{ display: "flex", flexDirection: "column", gap: 1 }}>
              <button onClick={() => movePhase(i, -1)} disabled={i === 0} style={{ background: "none", border: "none", color: i === 0 ? S.bd : S.dim, cursor: i === 0 ? "default" : "pointer", fontSize: 10, padding: 0, lineHeight: 1 }}>▲</button>
              <button onClick={() => movePhase(i, 1)} disabled={i === phases.length - 1} style={{ background: "none", border: "none", color: i === phases.length - 1 ? S.bd : S.dim, cursor: i === phases.length - 1 ? "default" : "pointer", fontSize: 10, padding: 0, lineHeight: 1 }}>▼</button>
            </div>
            <div style={{ fontSize: 10, color: S.dim, fontFamily: S.mo, textAlign: "center" }}>{i + 1}</div>
            <input type="color" value={p.color} onChange={(e) => updatePhase(i, "color", e.target.value)} style={{ width: 12, height: 12, border: "none", padding: 0, cursor: "pointer", background: "transparent" }} />
            <Inp value={p.name} onChange={(v) => updatePhase(i, "name", v)} style={{ padding: "5px 8px", fontSize: 12 }} />
            <div style={{ display: "flex", alignItems: "center", gap: 4 }}>
              <Inp type="number" value={p.months} onChange={(v) => updatePhase(i, "months", v)} mono style={{ padding: "5px 6px", fontSize: 11, textAlign: "center" }} />
              <span style={{ fontSize: 9, color: S.dim, whiteSpace: "nowrap" }}>mo</span>
            </div>
            <button onClick={() => removePhase(i)} disabled={phases.length <= 1} style={{ background: "none", border: "none", color: phases.length <= 1 ? S.bd : "#ef4444", cursor: phases.length <= 1 ? "default" : "pointer", fontSize: 12 }}>✕</button>
            <div />
          </div>
        ))}
      </div>
    </div>
  );
}

/* ─── SettingsForm ─── */
function SettingsForm({ project, onSave, onClose, studioUsers, studioPlatforms }) {
  const isMobile = typeof window !== "undefined" && window.innerWidth < 768;
  const [name, setName] = useState(project.name);
  const [studio, setStudio] = useState(project.studio);
  const [startDate, setStartDate] = useState(project.startDate);
  const [monthCount, setMonthCount] = useState(project.monthCount);
  const [glStartDate, setGlStartDate] = useState(project.glStartDate || project.startDate);
  const [glMonthCount, setGlMonthCount] = useState(project.glMonthCount || project.monthCount);
  const [multiCurrency, setMultiCurrency] = useState(project.multiCurrency || false);
  const [altCurrency, setAltCurrency] = useState(project.altCurrency || "EUR");
  const [globalSpotRate, setGlobalSpotRate] = useState(project.globalSpotRate || "");
  const [pointPerson, setPointPerson] = useState(Array.isArray(project.pointPerson) ? project.pointPerson : project.pointPerson ? [project.pointPerson] : []);
  const [platforms, setPlatforms] = useState(project.platforms || []);
  const [targetReleaseDate, setTargetReleaseDate] = useState(project.targetReleaseDate || "");
  const PLATFORM_OPTIONS = studioPlatforms || ["Steam", "EGS", "PlayStation 4", "PlayStation 5", "Xbox One", "Xbox Series X|S", "Switch", "Switch 2", "iOS", "Android", "Netflix"];

  const ccyList = ["EUR","GBP","CAD","AUD","JPY","CHF","SEK","NOK","DKK","PLN","CZK","HUF","BRL","MXN","CNY","KRW","INR","NZD","SGD","HKD"];

  const clampedMonths = Math.max(1, Math.min(120, Number(monthCount) || 36));
  const previewMs = useMemo(() => buildMonths(startDate, clampedMonths), [startDate, clampedMonths]);
  const startLabel = previewMs.length > 0 ? previewMs[0].label : "\u2014";
  const endLabel = previewMs.length > 0 ? previewMs[previewMs.length - 1].label : "\u2014";
  const glPreview = useMemo(() => buildMonths(glStartDate, Math.max(1, Math.min(120, Number(glMonthCount) || 36))), [glStartDate, glMonthCount]);
  const glStartLabel = glPreview.length > 0 ? glPreview[0].label : "\u2014";
  const glEndLabel = glPreview.length > 0 ? glPreview[glPreview.length - 1].label : "\u2014";

  const handleSave = () => {
    const mc = clampedMonths;
    const ms = buildMonths(startDate, mc);
    const pa = buildPhaseAssignment(project.phases, ms.map(m => m.key));
    onSave({ name, studio, startDate, monthCount: mc, glStartDate, glMonthCount: Math.max(1, Math.min(120, Number(glMonthCount) || 36)), phaseAssignment: pa, multiCurrency, altCurrency, globalSpotRate, pointPerson, platforms, targetReleaseDate });
    onClose();
  };

  const handleReset = () => {
    if (confirm("Reset all project data to defaults? This cannot be undone.")) {
      onSave("RESET");
      onClose();
    }
  };

  const secStyle = { padding: "16px 20px", background: S.bg, borderRadius: 10, marginBottom: 14 };
  const secTitle = (icon, text) => <div style={{ fontSize: 12, fontWeight: 700, color: S.tx, marginBottom: 14, display: "flex", alignItems: "center", gap: 8 }}><span style={{ fontSize: 14 }}>{icon}</span>{text}</div>;
  const fieldLabel = { fontSize: 10, color: S.dim, display: "block", marginBottom: 4, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.04em" };
  const monthInput = { width: "100%", padding: "8px 10px", background: S.sf, border: "1px solid " + S.bd, borderRadius: 6, color: S.tx, fontSize: 12, fontFamily: S.fn, outline: "none", boxSizing: "border-box", colorScheme: "dark" };
  const previewPill = (label, value, color) => <div style={{ display: "flex", alignItems: "center", gap: 6 }}><span style={{ fontSize: 10, color: S.dim }}>{label}</span><span style={{ fontSize: 12, fontWeight: 700, fontFamily: S.mo, color: color || S.tx }}>{value}</span></div>;

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 0 }}>

      {/* ── Project Identity ── */}
      <div style={secStyle}>
        {secTitle("🎬", "Project")}
        <div style={{ display: "grid", gridTemplateColumns: isMobile ? "1fr" : "1fr 1fr", gap: 12, marginBottom: 12 }}>
          <div><label style={fieldLabel}>Project Name</label><Inp value={name} onChange={setName} /></div>
          <div><label style={fieldLabel}>Studio</label><Inp value={studio} onChange={setStudio} /></div>
        </div>
        <div style={{ display: "grid", gridTemplateColumns: isMobile ? "1fr" : "1fr 1fr", gap: 12, marginBottom: 12 }}>
          <div><label style={fieldLabel}>Point Person(s)</label>
            <div style={{ display: "flex", gap: 4, flexWrap: "wrap" }}>
              {studioUsers.map(u => { const sel = pointPerson.includes(u.name); return <button key={u.id} type="button" onClick={() => setPointPerson(prev => sel ? prev.filter(n => n !== u.name) : [...prev, u.name])} className="fcc-chip" style={{ padding: "5px 10px", background: sel ? S.acc + "20" : "transparent", border: "1px solid " + (sel ? S.acc : S.bd), borderRadius: 6, color: sel ? S.acc : S.dim, fontSize: 10, fontWeight: 600, cursor: "pointer", fontFamily: S.fn }}>{sel ? "\u2713 " : ""}{u.name}</button>; })}
            </div>
          </div>
          <div><label style={fieldLabel}>Target Release Date</label><input type="month" value={targetReleaseDate} onChange={(e) => setTargetReleaseDate(e.target.value)} style={{ width: "100%", padding: "7px 10px", background: S.bg, border: "1px solid " + S.bd, borderRadius: 6, color: S.tx, fontSize: 12, fontFamily: S.fn, outline: "none", boxSizing: "border-box", colorScheme: "dark" }} /></div>
        </div>
        <div>
          <label style={fieldLabel}>Platforms</label>
          <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
            {PLATFORM_OPTIONS.map(p => {
              const sel = platforms.includes(p);
              return <button key={p} type="button" onClick={() => setPlatforms(prev => sel ? prev.filter(x => x !== p) : [...prev, p])} className="fcc-chip" style={{ padding: "5px 12px", background: sel ? S.acc + "20" : "transparent", border: "1px solid " + (sel ? S.acc : S.bd), borderRadius: 6, color: sel ? S.acc : S.dim, fontSize: 10, fontWeight: 600, cursor: "pointer", fontFamily: S.fn }}>{sel ? "✓ " : ""}{p}</button>;
            })}
          </div>
        </div>
      </div>

      {/* ── Live Timeline ── */}
      <div style={secStyle}>
        {secTitle("📅", "Live Timeline")}
        <div style={{ display: "grid", gridTemplateColumns: isMobile ? "1fr" : "1fr 1fr", gap: 12, marginBottom: 12 }}>
          <div><label style={fieldLabel}>Start Month</label><input type="month" value={startDate} onChange={(e) => setStartDate(e.target.value)} style={monthInput} /></div>
          <div><label style={fieldLabel}>Duration (months)</label><Inp type="number" value={monthCount} onChange={(v) => setMonthCount(v)} mono /></div>
        </div>
        <div style={{ display: "flex", gap: 20, padding: "10px 14px", background: S.sf, borderRadius: 8, flexWrap: "wrap" }}>
          {previewPill("Start", startLabel, S.grn)}
          <span style={{ color: S.bd2 }}>→</span>
          {previewPill("End", endLabel, S.grn)}
          {previewPill("Duration", clampedMonths + " mo")}
          {previewPill("Phases", project.phases.length + " phases", S.acc)}
        </div>
      </div>

      {/* ── Greenlit Timeline ── */}
      <div style={secStyle}>
        {secTitle("🔒", "Greenlit Timeline")}
        <div style={{ display: "grid", gridTemplateColumns: isMobile ? "1fr" : "1fr 1fr", gap: 12, marginBottom: 12 }}>
          <div><label style={fieldLabel}>GL Start Month</label><input type="month" value={glStartDate} onChange={(e) => setGlStartDate(e.target.value)} style={monthInput} /></div>
          <div><label style={fieldLabel}>GL Duration (months)</label><input type="number" value={glMonthCount} onChange={(e) => setGlMonthCount(e.target.value)} min={1} max={120} style={{ ...monthInput, fontFamily: S.mo }} /></div>
        </div>
        <div style={{ display: "flex", gap: 20, padding: "10px 14px", background: S.sf, borderRadius: 8, flexWrap: "wrap" }}>
          {previewPill("Start", glStartLabel, S.acc)}
          <span style={{ color: S.bd2 }}>→</span>
          {previewPill("End", glEndLabel, S.acc)}
          {previewPill("Duration", glPreview.length + " mo")}
          {previewPill("Phases", project.phases.length + " phases", S.acc)}
        </div>
      </div>

      {/* ── Currency ── */}
      <div style={secStyle}>
        {secTitle("💱", "Currency")}
        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: multiCurrency ? 14 : 0 }}>
          <button onClick={() => setMultiCurrency(!multiCurrency)} className="fcc-chip" style={{ width: 44, height: 24, borderRadius: 12, border: "none", background: multiCurrency ? S.acc : S.bd2, cursor: "pointer", position: "relative", transition: "background 0.2s", flexShrink: 0 }}>
            <span style={{ position: "absolute", top: 3, left: multiCurrency ? 23 : 3, width: 18, height: 18, borderRadius: 9, background: "#fff", transition: "left 0.2s" }} />
          </button>
          <div>
            <div style={{ fontSize: 12, fontWeight: 600, color: S.tx }}>{multiCurrency ? "Multi-Currency Enabled" : "Single Currency (USD)"}</div>
            <div style={{ fontSize: 10, color: S.dim, marginTop: 1 }}>{multiCurrency ? "Developer fees tracked in " + altCurrency + ". Other rows toggleable." : "All line items tracked in USD."}</div>
          </div>
        </div>
        {multiCurrency && (
          <div style={{ padding: "14px 16px", background: S.sf, borderRadius: 8, border: "1px solid " + S.bd }}>
            <div style={{ display: "grid", gridTemplateColumns: isMobile ? "1fr" : "1fr 1fr", gap: 12, marginBottom: 12 }}>
              <div>
                <label style={fieldLabel}>Developer Fee Currency</label>
                <Sel value={altCurrency} onChange={setAltCurrency}>{ccyList.map(c => <option key={c} value={c}>{c}</option>)}</Sel>
              </div>
              <div>
                <label style={fieldLabel}>Global Rate (1 {altCurrency} = ? USD)</label>
                <Inp type="text" value={globalSpotRate} onChange={(v) => setGlobalSpotRate(v)} placeholder={FX_RATES[altCurrency] ? String(FX_RATES[altCurrency]) : "1.0000"} mono />
              </div>
            </div>
            <div style={{ fontSize: 10, color: S.dim, lineHeight: 1.5, marginBottom: 10 }}>
              All <strong style={{ color: "#fbbf24" }}>Developer Fees</strong> use {altCurrency}. The global rate applies to any month without a specific override. You can still override individual months on the Budget Grid FX rate row.
            </div>
            <button onClick={() => {
              const rate = globalSpotRate || (FX_RATES[altCurrency] ? String(FX_RATES[altCurrency]) : "1.0");
              setGlobalSpotRate(rate);
            }} className="fcc-btn-ghost" style={{ padding: "5px 12px", background: "none", border: "1px solid " + S.bd, borderRadius: 6, color: S.dim, fontSize: 10, fontFamily: S.fn, fontWeight: 600, cursor: "pointer" }}>Set from market rate (1 {altCurrency} = {FX_RATES[altCurrency] ? FX_RATES[altCurrency] + " USD" : "N/A"})</button>
          </div>
        )}
      </div>


      {/* ── Actions ── */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "10px 0 0" }}>
        <Btn danger small onClick={handleReset}>Reset to Defaults</Btn>
        <div style={{ display: "flex", gap: 8 }}>
          <Btn onClick={onClose}>Cancel</Btn>
          <Btn primary onClick={handleSave}>Save Changes</Btn>
        </div>
      </div>
    </div>
  );
}


