        if (e.key === "ArrowLeft") { e.preventDefault(); const nmi = Math.max(0, mi - 1); setActiveCell({ ri, mi: nmi }); setSel({ r1: ri, m1: nmi, r2: ri, m2: nmi }); return; }
        if (e.key === "ArrowDown") { e.preventDefault(); const nri = Math.min(visibleRowIds.length - 1, ri + 1); setActiveCell({ ri: nri, mi }); setSel({ r1: nri, m1: mi, r2: nri, m2: mi }); return; }
        if (e.key === "ArrowUp") { e.preventDefault(); const nri = Math.max(0, ri - 1); setActiveCell({ ri: nri, mi }); setSel({ r1: nri, m1: mi, r2: nri, m2: mi }); return; }
        if (e.key === "Tab") { e.preventDefault(); const nmi = e.shiftKey ? Math.max(0, mi - 1) : Math.min(ms.length - 1, mi + 1); setActiveCell({ ri, mi: nmi }); setSel({ r1: ri, m1: nmi, r2: ri, m2: nmi }); return; }
        if (e.key === "Enter") { e.preventDefault(); const nri = Math.min(visibleRowIds.length - 1, ri + 1); setActiveCell({ ri: nri, mi }); setSel({ r1: nri, m1: mi, r2: nri, m2: mi }); return; }
