      const context = aiDeepMode ? JSON.stringify({ project: { name: project.name, studio: project.studio, glVersion: project.greenlitVersion || 1 }, timeline: { start: projMs[0]?.label, end: projMs[projMs.length-1]?.label, months: projMs.length, currentPhase: currentPhaseName }, summary: { liveBudget: liveTot, greenlitBudget: glTot, variance }, groupTotals, phaseBreakdown, monthlyTotals, allLineItems: allRowsData.map(r => { const row = project.rows.find(rr => (rr.meta.role||rr.meta.item) === r.name && (rr.meta.department||rr.meta.category) === r.dept); const lm = {}, gm2 = {}; if (row) projMs.forEach(m => { const lv = Number(row.live?.[m.key])||0; const gv = Number(row.greenlit?.[m.key])||0; if(lv) lm[m.label]=lv; if(gv) gm2[m.label]=gv; }); return { ...r, liveMonths: lm, glMonths: gm2 }; }), milestonePayments: Object.entries(project.milestonePayment||{}).filter(([,v])=>v).map(([k,v])=>({month:k,amount:v})) }, null, 0)
        : JSON.stringify({ project: { name: project.name, studio: project.studio, glVersion: project.greenlitVersion || 1 }, timeline: { start: projMs[0]?.label, end: projMs[projMs.length-1]?.label, months: projMs.length, currentPhase: currentPhaseName }, summary: { liveBudget: liveTot, greenlitBudget: glTot, variance }, groupTotals, phaseBreakdown, topItems: allRowsData.sort((a,b)=>b.liveTotal-a.liveTotal).slice(0,10), itemCount: allRowsData.length }, null, 0);
