            <button onClick={redo} disabled={redoLen === 0} title="Redo" className="fcc-icon-btn" style={{ background: "none", border: "none", cursor: redoLen > 0 ? "pointer" : "default", padding: "4px 6px", borderRadius: 5, display: "flex", alignItems: "center", opacity: redoLen > 0 ? 1 : 0.3 }}><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#e2e8f0" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="23 4 23 10 17 10"/><path d="M20.49 15a9 9 0 1 1-2.13-9.36L23 10"/></svg></button>
