                const cl = (ii < p2.tiers.length - 1 && p2.tiers[ii + 1].thType !== "onwards") ? tc[ii + 1] : Infinity;
                const tr = Math.max(0, Math.min(nr, cl) - cm); if (tr <= 0) break;
