      <style>{`@import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@300;400;500;600;700;800&family=JetBrains+Mono:wght@400;500&display=swap');*{box-sizing:border-box;margin:0;padding:0}.fcc-btn{transition:all 0.15s ease;position:relative}.fcc-btn:hover{filter:brightness(1.2);background-color:rgba(99,102,241,0.1);box-shadow:0 2px 10px rgba(99,102,241,0.2);transform:translateY(-1px)}.fcc-btn:active{transform:translateY(0);filter:brightness(1.05)}.fcc-btn-primary:hover{box-shadow:0 4px 14px rgba(99,102,241,0.4)!important}.fcc-btn-danger:hover{box-shadow:0 4px 14px rgba(239,68,68,0.3)!important;filter:brightness(1.3)}.fcc-btn-ghost{transition:all 0.15s ease}.fcc-btn-ghost:hover{background:rgba(99,102,241,0.08)!important;color:#e2e8f0!important}.fcc-tab{transition:all 0.15s ease}.fcc-tab:hover{background:rgba(99,102,241,0.06)!important;color:#e2e8f0!important}.fcc-nav{transition:all 0.15s ease}.fcc-nav:hover{background:rgba(99,102,241,0.1)!important;color:#c7d2fe!important}.fcc-icon-btn{transition:all 0.15s ease;border-radius:6px}.fcc-icon-btn:hover{background:rgba(99,102,241,0.12)!important;transform:scale(1.05)}.fcc-icon-btn:active{transform:scale(0.97)}.fcc-row-btn{transition:all 0.12s ease}.fcc-row-btn:hover{background:rgba(99,102,241,0.15)!important;border-color:#6366f1!important}.fcc-card-pick{transition:all 0.2s ease;transform-origin:center}.fcc-card-pick:hover{transform:translateY(-2px);box-shadow:0 6px 20px rgba(0,0,0,0.3)}.fcc-card-indigo:hover{border-color:#6366f1!important;box-shadow:0 6px 24px rgba(99,102,241,0.25)!important;background:rgba(99,102,241,0.06)!important}.fcc-card-green:hover{border-color:#10b981!important;box-shadow:0 6px 24px rgba(16,185,129,0.25)!important;background:rgba(16,185,129,0.06)!important}.fcc-card-amber:hover{border-color:#f59e0b!important;box-shadow:0 6px 24px rgba(245,158,11,0.25)!important;background:rgba(245,158,11,0.06)!important}.fcc-chip{transition:all 0.15s ease}.fcc-chip:hover{filter:brightness(1.3);transform:translateY(-1px)}`}</style>
