                <div style={{ width: 36, height: 36, borderRadius: 10, background: r.color + "20", color: r.color, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 15, fontWeight: 800 }}>{u.name[0].toUpperCase()}</div>
